// C solution (uses direct strings – acceptable for the small limits used in the statement)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007LL

int cmp(const void *a, const void *b, void *arg) {
    const int *ia = a, *ib = b;
    const char **s = arg;
    const char *sa = s[*ia];
    const char *sb = s[*ib];
    int r = strcmp(sa, sb);
    if (r != 0) return r;
    return (*ia) - (*ib);
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        char S[10000005]; scanf("%s", S);
        int M = N - K + 1;
        char **arr = (char**)malloc(M * sizeof(char*));
        for(int i=0;i<M;i++){
            int len = N - K;
            arr[i] = (char*)malloc((len+1)*sizeof(char));
            int pos = 0;
            // copy left part
            for(int j=0;j<i;j++) arr[i][pos++] = S[j];
            // copy right part
            for(int j=i+K;j<N;j++) arr[i][pos++] = S[j];
            arr[i][pos] = '\0';
        }
        int *idx = (int*)malloc(M * sizeof(int));
        for(int i=0;i<M;i++) idx[i]=i;
        qsort_r(idx, M, sizeof(int), cmp, arr);
        long long ans=0;
        for(int i=0;i<M;i++){
            long long p = idx[i]+1; // original index is 1‑based
            ans = (ans + p * (i+1)) % MOD;
        }
        printf("%lld\n", ans);
        for(int i=0;i<M;i++) free(arr[i]);
        free(arr); free(idx);
    }
    return 0;
}

