// C++17 solution using rolling hash for full constraints
#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;
const long long BASE = 91138233LL;

struct RH {
    vector<long long> pref, powb;
    RH(const string &s){
        int n = s.size();
        pref.resize(n+1,0);
        powb.resize(n+1,1);
        for(int i=0;i<n;i++){
            pref[i+1] = (pref[i]*BASE + (s[i]-'a'+1))%MOD;
            powb[i+1] = (powb[i]*BASE)%MOD;
        }
    }
    // hash of s[l..r) 0‑based
    long long get(int l,int r) const{
        long long h = (pref[r] - pref[l]*powb[r-l])%MOD;
        if(h<0) h+=MOD;
        return h;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,K; cin>>N>>K; string S; cin>>S;
        int M = N - K + 1;
        RH rh(S);
        auto getHashPrefix = [&](int idx, int len)->long long{
            // prefix of f(idx) of length len, idx is 0‑based (i = idx+1)
            int leftLen = idx; // characters before deletion
            if(len <= leftLen){
                return rh.get(0, len);
            }else{
                long long leftHash = rh.get(0, leftLen);
                int need = len - leftLen; // from right part
                long long rightHash = rh.get(idx+K, idx+K+need);
                return ( (leftHash * rh.powb[need])%MOD + rightHash )%MOD;
            }
        };
        auto charAt = [&](int idx, int pos)->char{
            // character at position pos (0‑based) of f(idx)
            int leftLen = idx;
            if(pos < leftLen) return S[pos];
            else return S[pos+K];
        };
        vector<int> ids(M);
        iota(ids.begin(), ids.end(), 0);
        auto cmp = [&](int a, int b){
            if(a==b) return false;
            int len = N - K;
            int lo=0, hi=len;
            while(lo<hi){
                int mid = (lo+hi+1)/2;
                if(getHashPrefix(a,mid)==getHashPrefix(b,mid)) lo=mid; else hi=mid-1;
            }
            if(lo==len) return a<b; // equal strings
            char ca = charAt(a, lo);
            char cb = charAt(b, lo);
            if(ca!=cb) return ca<cb;
            return a<b;
        };
        sort(ids.begin(), ids.end(), [&](int x,int y){return cmp(x,y);} );
        long long ans=0;
        for(int i=0;i<M;i++){
            long long p = ids[i]+1; // 1‑based index
            ans = (ans + p * (i+1)) % MOD;
        }
        cout<<ans<<"\n";
    }
    return 0;
}
